import Foundation

// Simulated async functions
func fetchUserName(id: Int) async -> String {
    try? await Task.sleep(nanoseconds: 100_000_000) // 0.1 seconds
    return "User \(id)"
}

func fetchUserEmail(id: Int) async -> String {
    try? await Task.sleep(nanoseconds: 100_000_000)
    return "user\(id)@example.com"
}

// Sequential execution
Task {
    print("Fetching user info sequentially...")
    let start = Date()

    let name = await fetchUserName(id: 1)
    let email = await fetchUserEmail(id: 1)

    let time = Date().timeIntervalSince(start)
    print("Name: \(name)")
    print("Email: \(email)")
    print("Time: \(String(format: "%.2f", time))s")

    // Now try parallel
    print("\nFetching user info in parallel...")
    let start2 = Date()

    async let nameParallel = fetchUserName(id: 1)
    async let emailParallel = fetchUserEmail(id: 1)

    let (nameResult, emailResult) = await (nameParallel, emailParallel)
    let time2 = Date().timeIntervalSince(start2)

    print("Name: \(nameResult)")
    print("Email: \(emailResult)")
    print("Time: \(String(format: "%.2f", time2))s")
}

